jQuery(function($){$('.-action.-bootstrap-qrcode').on('show.bs.dropdown',function(event){if($(this).data('qrcode'))return;const $wrap=$(this).find('.-qrcode-wrap');const $link=$(this).find('a.bootstrap-qrcode-toggle');const size=$link.data('qrcode-size');$wrap.html($('<img />',{src:'https://api.qrserver.com/v1/create-qr-code/?size='+size+'x'+size+'&ecc=M&data='+encodeURIComponent($link.data('qrcode-url')),alt:'qrcode',class:'bootstrap-qrcode-img'}));$(this).data('qrcode',true);$(this).find('.-qrcode-wrap img').on('error',function(event){$wrap.html('<div class="-na d-flex align-items-center justify-content-center h-100 py-3"><small>'+$link.data('na')+'</small></div>');});});});
